import { createHmac, randomUUID, timingSafeEqual } from "node:crypto";

export type ReturnToPolicy =
  | { kind: "relative-only" }
  | { kind: "allowed-origins"; allowedOrigins: string[] };

export type AppCookieNames = {
  auth: string;
  refresh: string;
  id: string;
};

export type AppConfig = {
  slug: string;
  allowedOrigins: string[];
  returnToPolicy: ReturnToPolicy;
  cookieNames: AppCookieNames;
  cookieDomain: string;
  sessionSecret: string;
  cognitoClientId?: string;
};

type RawAppEntry = {
  allowedOrigins?: unknown;
  returnToPolicy?: unknown;
  cookieNames?: unknown;
  cookieDomain?: unknown;
  sessionSecret?: unknown;
  sessionSecretEnv?: unknown;
  cognitoClientId?: unknown;
};

const DEFAULT_COOKIE_NAMES: AppCookieNames = {
  auth: "authToken",
  refresh: "refreshToken",
  id: "idToken",
};

const AUTH_STATE_TTL_SECONDS = 600;

export class AppRegistryError extends Error {
  readonly reason:
    | "missing_env"
    | "invalid_json"
    | "unknown_app"
    | "missing_secret";

  constructor(
    reason: AppRegistryError["reason"],
    message: string,
  ) {
    super(message);
    this.name = "AppRegistryError";
    this.reason = reason;
  }
}

function parseRegistryEnv(): Record<string, RawAppEntry> | null {
  const raw = process.env.AUTH_APPS?.trim();
  if (!raw) return null;

  const tryParse = (value: string): unknown => {
    try {
      return JSON.parse(value);
    } catch {
      return undefined;
    }
  };

  let parsed = tryParse(raw);
  if (typeof parsed === "string") {
    parsed = tryParse(parsed);
  }
  if (parsed && typeof parsed === "object" && !Array.isArray(parsed)) {
    return parsed as Record<string, RawAppEntry>;
  }

  const trimmed = raw.trim();
  if (trimmed.startsWith("'") && trimmed.endsWith("'")) {
    const unwrapped = tryParse(trimmed.slice(1, -1));
    if (unwrapped && typeof unwrapped === "object" && !Array.isArray(unwrapped)) {
      return unwrapped as Record<string, RawAppEntry>;
    }
  }

  const escaped = tryParse(raw.replace(/\\"/g, '"'));
  if (escaped && typeof escaped === "object" && !Array.isArray(escaped)) {
    return escaped as Record<string, RawAppEntry>;
  }

  return null;
}

function asStringArray(value: unknown): string[] {
  if (!Array.isArray(value)) return [];
  return value.filter((item): item is string => typeof item === "string");
}

function normalizeOrigin(origin: string): string | null {
  try {
    const url = new URL(origin);
    return url.origin;
  } catch {
    return null;
  }
}

function parseReturnToPolicy(raw: unknown): ReturnToPolicy {
  if (raw === undefined || raw === null || raw === "relative-only") {
    return { kind: "relative-only" };
  }
  if (typeof raw === "object" && raw !== null) {
    const candidate = raw as { allowedOrigins?: unknown };
    const origins = asStringArray(candidate.allowedOrigins)
      .map(normalizeOrigin)
      .filter((origin): origin is string => origin !== null);
    if (origins.length > 0) {
      return { kind: "allowed-origins", allowedOrigins: origins };
    }
  }
  return { kind: "relative-only" };
}

function parseCookieNames(raw: unknown): AppCookieNames {
  if (typeof raw !== "object" || raw === null) {
    return { ...DEFAULT_COOKIE_NAMES };
  }
  const candidate = raw as Partial<AppCookieNames>;
  return {
    auth:
      typeof candidate.auth === "string" && candidate.auth
        ? candidate.auth
        : DEFAULT_COOKIE_NAMES.auth,
    refresh:
      typeof candidate.refresh === "string" && candidate.refresh
        ? candidate.refresh
        : DEFAULT_COOKIE_NAMES.refresh,
    id:
      typeof candidate.id === "string" && candidate.id
        ? candidate.id
        : DEFAULT_COOKIE_NAMES.id,
  };
}

function resolveSessionSecret(entry: RawAppEntry, slug: string): string {
  if (typeof entry.sessionSecret === "string" && entry.sessionSecret.trim()) {
    return entry.sessionSecret.trim();
  }
  if (
    typeof entry.sessionSecretEnv === "string" &&
    entry.sessionSecretEnv.trim()
  ) {
    const envName = entry.sessionSecretEnv.trim();
    const value = process.env[envName]?.trim();
    if (!value) {
      throw new AppRegistryError(
        "missing_secret",
        `Missing env var ${envName} referenced by AUTH_APPS["${slug}"].sessionSecretEnv.`,
      );
    }
    if (value.length < 32) {
      throw new AppRegistryError(
        "missing_secret",
        `Env var ${envName} must be at least 32 characters long.`,
      );
    }
    return value;
  }
  throw new AppRegistryError(
    "missing_secret",
    `AUTH_APPS["${slug}"] must specify either sessionSecret or sessionSecretEnv.`,
  );
}

function buildAppConfig(slug: string, entry: RawAppEntry): AppConfig {
  const allowedOrigins = asStringArray(entry.allowedOrigins)
    .map(normalizeOrigin)
    .filter((origin): origin is string => origin !== null);

  const returnToPolicy = parseReturnToPolicy(entry.returnToPolicy);
  const cookieNames = parseCookieNames(entry.cookieNames);
  const cookieDomain =
    typeof entry.cookieDomain === "string" ? entry.cookieDomain : "";
  const sessionSecret = resolveSessionSecret(entry, slug);
  const cognitoClientId =
    typeof entry.cognitoClientId === "string" && entry.cognitoClientId
      ? entry.cognitoClientId
      : undefined;

  return {
    slug,
    allowedOrigins,
    returnToPolicy,
    cookieNames,
    cookieDomain,
    sessionSecret,
    cognitoClientId,
  };
}

export function listAppSlugs(): string[] {
  const registry = parseRegistryEnv();
  if (!registry) return [];
  return Object.keys(registry);
}

export function resolveAppConfig(slug: string): AppConfig {
  const registry = parseRegistryEnv();
  if (!registry) {
    throw new AppRegistryError(
      "missing_env",
      "AUTH_APPS env var is not set; no app integrations are configured.",
    );
  }
  const entry = registry[slug];
  if (!entry || typeof entry !== "object") {
    throw new AppRegistryError(
      "unknown_app",
      `Unknown app slug "${slug}" — not present in AUTH_APPS.`,
    );
  }
  return buildAppConfig(slug, entry);
}

export function tryResolveAppConfig(slug: string): AppConfig | null {
  try {
    return resolveAppConfig(slug);
  } catch (err) {
    if (err instanceof AppRegistryError) {
      return null;
    }
    throw err;
  }
}

export function isAllowedReturnTo(app: AppConfig, value: string): boolean {
  if (typeof value !== "string" || value.length === 0) return false;

  if (app.returnToPolicy.kind === "relative-only") {
    if (!value.startsWith("/")) return false;
    if (value.startsWith("//")) return false;
    if (value.startsWith("/\\")) return false;
    if (value.includes("\\")) return false;
    return true;
  }

  try {
    const url = new URL(value);
    return app.returnToPolicy.allowedOrigins.includes(url.origin);
  } catch {
    return false;
  }
}

export function pickReturnToTarget(
  app: AppConfig,
  returnTo: string,
): string | null {
  if (!isAllowedReturnTo(app, returnTo)) return null;

  if (app.returnToPolicy.kind === "allowed-origins") {
    return returnTo;
  }

  const origin = app.allowedOrigins[0];
  if (!origin) return null;
  return `${origin}${returnTo}`;
}

export type AuthStatePayload = {
  slug: string;
  returnTo: string;
  nonce: string;
  iat: number;
};

function base64url(input: string | Buffer): string {
  return Buffer.from(input).toString("base64url");
}

function fromBase64url(value: string): Buffer {
  return Buffer.from(value, "base64url");
}

function hmacSign(secret: string, data: string): string {
  return createHmac("sha256", secret).update(data).digest("base64url");
}

export function signAuthState(
  app: AppConfig,
  payload: Omit<AuthStatePayload, "iat" | "nonce"> & {
    nonce?: string;
    iat?: number;
  },
): string {
  if (payload.slug !== app.slug) {
    throw new Error("auth_state slug does not match app slug.");
  }
  const fullPayload: AuthStatePayload = {
    slug: payload.slug,
    returnTo: payload.returnTo,
    nonce: payload.nonce ?? randomUUID(),
    iat: payload.iat ?? Math.floor(Date.now() / 1000),
  };
  const body = base64url(JSON.stringify(fullPayload));
  const sig = hmacSign(app.sessionSecret, body);
  return `${body}.${sig}`;
}

export type VerifyAuthStateResult =
  | { ok: true; payload: AuthStatePayload }
  | {
      ok: false;
      reason:
        | "malformed"
        | "bad_signature"
        | "slug_mismatch"
        | "expired"
        | "invalid_payload";
    };

export function verifyAuthState(
  app: AppConfig,
  token: string,
  options: { nowSeconds?: number; maxAgeSeconds?: number } = {},
): VerifyAuthStateResult {
  if (typeof token !== "string" || token.length === 0) {
    return { ok: false, reason: "malformed" };
  }
  const parts = token.split(".");
  if (parts.length !== 2) {
    return { ok: false, reason: "malformed" };
  }
  const [body, providedSig] = parts;
  const expectedSig = hmacSign(app.sessionSecret, body);
  const a = fromBase64url(providedSig);
  const b = fromBase64url(expectedSig);
  if (a.length !== b.length || !timingSafeEqual(a, b)) {
    return { ok: false, reason: "bad_signature" };
  }

  let payload: AuthStatePayload;
  try {
    const decoded = JSON.parse(fromBase64url(body).toString("utf8"));
    if (
      !decoded ||
      typeof decoded !== "object" ||
      typeof decoded.slug !== "string" ||
      typeof decoded.returnTo !== "string" ||
      typeof decoded.nonce !== "string" ||
      typeof decoded.iat !== "number"
    ) {
      return { ok: false, reason: "invalid_payload" };
    }
    payload = decoded as AuthStatePayload;
  } catch {
    return { ok: false, reason: "invalid_payload" };
  }

  if (payload.slug !== app.slug) {
    return { ok: false, reason: "slug_mismatch" };
  }
  const now = options.nowSeconds ?? Math.floor(Date.now() / 1000);
  const maxAge = options.maxAgeSeconds ?? AUTH_STATE_TTL_SECONDS;
  if (now - payload.iat > maxAge) {
    return { ok: false, reason: "expired" };
  }
  return { ok: true, payload };
}

import { useSession } from "@tanstack/react-start/server";
import type { AuthenticationResultType } from "@aws-sdk/client-cognito-identity-provider";
import type { AppConfig } from "./app-integration";

export type AppTokenSet = {
  accessToken: string;
  idToken: string;
  refreshToken?: string;
  expiresIn?: number;
};

export type AppAuthCookieState = { authToken?: string };
export type AppRefreshCookieState = { refreshToken?: string };
export type AppIdCookieState = { idToken?: string };

const ACCESS_TOKEN_DEFAULT_TTL = 3500;
const REFRESH_TOKEN_DEFAULT_TTL = 60 * 60 * 24 * 30;
const ID_TOKEN_DEFAULT_TTL = 3500;

function isProduction(): boolean {
  return process.env.NODE_ENV === "production";
}

function cookieDomainOption(app: AppConfig): string | undefined {
  return app.cookieDomain && app.cookieDomain.length > 0
    ? app.cookieDomain
    : undefined;
}

export async function useAppAuthTokenSession(app: AppConfig) {
  return useSession<AppAuthCookieState>({
    name: app.cookieNames.auth,
    password: app.sessionSecret,
    cookie: {
      domain: cookieDomainOption(app),
      httpOnly: true,
      maxAge: ACCESS_TOKEN_DEFAULT_TTL,
      path: "/",
      sameSite: "lax",
      secure: isProduction(),
    },
  });
}

export async function useAppRefreshTokenSession(app: AppConfig) {
  return useSession<AppRefreshCookieState>({
    name: app.cookieNames.refresh,
    password: app.sessionSecret,
    cookie: {
      domain: cookieDomainOption(app),
      httpOnly: true,
      maxAge: REFRESH_TOKEN_DEFAULT_TTL,
      path: "/",
      sameSite: "lax",
      secure: isProduction(),
    },
  });
}

export async function useAppIdTokenSession(app: AppConfig) {
  return useSession<AppIdCookieState>({
    name: app.cookieNames.id,
    password: app.sessionSecret,
    cookie: {
      domain: cookieDomainOption(app),
      httpOnly: true,
      maxAge: ID_TOKEN_DEFAULT_TTL,
      path: "/",
      sameSite: "lax",
      secure: isProduction(),
    },
  });
}

function tokenSetFromCognito(
  authResult: AuthenticationResultType | undefined,
): AppTokenSet | null {
  if (!authResult?.AccessToken || !authResult?.IdToken) return null;
  return {
    accessToken: authResult.AccessToken,
    idToken: authResult.IdToken,
    refreshToken: authResult.RefreshToken,
    expiresIn: authResult.ExpiresIn,
  };
}

export async function writeAppTokenCookies(
  app: AppConfig,
  tokens: AppTokenSet,
): Promise<void> {
  // biome-ignore lint/correctness/useHookAtTopLevel: server function, not a React component
  const auth = await useAppAuthTokenSession(app);
  await auth.update({ authToken: tokens.accessToken });

  // biome-ignore lint/correctness/useHookAtTopLevel: server function, not a React component
  const id = await useAppIdTokenSession(app);
  await id.update({ idToken: tokens.idToken });

  if (tokens.refreshToken) {
    // biome-ignore lint/correctness/useHookAtTopLevel: server function, not a React component
    const refresh = await useAppRefreshTokenSession(app);
    await refresh.update({ refreshToken: tokens.refreshToken });
  }
}

export async function writeAppTokenCookiesFromCognito(
  app: AppConfig,
  authResult: AuthenticationResultType | undefined,
): Promise<boolean> {
  const tokens = tokenSetFromCognito(authResult);
  if (!tokens) return false;
  await writeAppTokenCookies(app, tokens);
  return true;
}

export async function clearAppTokenCookies(app: AppConfig): Promise<void> {
  // biome-ignore lint/correctness/useHookAtTopLevel: server function, not a React component
  const auth = await useAppAuthTokenSession(app);
  await auth.clear();
  // biome-ignore lint/correctness/useHookAtTopLevel: server function, not a React component
  const id = await useAppIdTokenSession(app);
  await id.clear();
  // biome-ignore lint/correctness/useHookAtTopLevel: server function, not a React component
  const refresh = await useAppRefreshTokenSession(app);
  await refresh.clear();
}

