  debug: z.coerce.boolean().default(false),
  identity_provider: z.enum(["Google"]).optional(),
  redirect_uri: httpsUrlSchema,
  response_type: z.literal("code").default("code"),
  scope: z.string().min(1).default("openid email"),
  session_url: httpsUrlSchema.optional(),
  state: z.string().min(1),
});

export const appAuthorizeSearchSchema = z.object({
  app: z.string().min(1),
  auth_state: z.string().min(1),
  debug: z.coerce.boolean().default(false),
  return_to: z.string().min(1),
  state: z.string().min(1).optional(),
});

export const authorizeSearchSchema = z.union([
  appAuthorizeSearchSchema,
  oauthAuthorizeSearchSchema,
]);

export type OauthAuthorizeSearch = z.infer<typeof oauthAuthorizeSearchSchema>;
export type AppAuthorizeSearch = z.infer<typeof appAuthorizeSearchSchema>;
export type AuthorizeSearch = z.infer<typeof authorizeSearchSchema>;

export function isAppAuthorize(
  value: AuthorizeSearch,
): value is AppAuthorizeSearch {
  return "app" in value && typeof value.app === "string";
}

export const oauthLogoutSearchSchema = z.object({
  redirect_url: httpsUrlSchema.optional(),
});

export const appLogoutSearchSchema = z.object({
  app: z.string().min(1),
  return_to: z.string().min(1).optional(),
});

export const logoutSearchSchema = z.union([
  appLogoutSearchSchema,
  oauthLogoutSearchSchema,
]);

export type OauthLogoutSearch = z.infer<typeof oauthLogoutSearchSchema>;
export type AppLogoutSearch = z.infer<typeof appLogoutSearchSchema>;
export type LogoutSearch = z.infer<typeof logoutSearchSchema>;

export function isAppLogout(value: LogoutSearch): value is AppLogoutSearch {
  return "app" in value && typeof value.app === "string";
}

