type ActiveAuthRequest =
  | { mode: "oauth"; oauth: OauthRequestState }
  | { mode: "app"; app: AppConfig; appRequest: AppRequestState };

function requireActiveRequest(
  sessionData: Awaited<ReturnType<typeof useTransactionSession>>["data"],
): ActiveAuthRequest {
  if (sessionData.appRequest) {
    let app: AppConfig;
    try {
      app = resolveAppConfig(sessionData.appRequest.slug);
    } catch (err) {
      if (err instanceof AppRegistryError) {
        throw redirect({
          to: "/error",
          search: { reason: "unknown_app" },
        });
      }
      throw err;
    }
    return { mode: "app", app, appRequest: sessionData.appRequest };
  }
  if (sessionData.oauthRequest) {
    return { mode: "oauth", oauth: sessionData.oauthRequest };
  }
  throw redirect({
    to: "/error",
    search: { reason: "missing_auth_context" },
  });
}

function requireOauthRequest(
  sessionData: Awaited<ReturnType<typeof useTransactionSession>>["data"],
) {
  const request = sessionData.oauthRequest;
  if (!request) {
    throw redirect({
      to: "/error",
      search: { reason: "missing_auth_context" },
    });
  }
  return request;
}

function redirectToAppReturn(
  app: AppConfig,
  appRequest: AppRequestState,
): never {
  const target = pickReturnToTarget(app, appRequest.returnTo);
  if (!target) {
    throw redirect({
      to: "/error",
      search: { reason: "invalid_return_to" },
    });
  }
  throw redirect({ href: target });
}

async function clearTransactionSession(): Promise<void> {
  // biome-ignore lint/correctness/useHookAtTopLevel: server function, not a React component
  const txSession = await useTransactionSession();
  await txSession.clear();
}

async function completeAuthSuccess(
  active: ActiveAuthRequest,
  authResult: AuthenticationResultType | undefined,
): Promise<never> {
  if (active.mode === "app") {
    const wrote = await writeAppTokenCookiesFromCognito(
