        if (result.ChallengeName === "NEW_PASSWORD_REQUIRED") {
          await txSession.update({
            ...txSession.data,
            challengeName: "NEW_PASSWORD_REQUIRED",
            challengeSession: result.Session,
            challengeUsername: data.email,
          });
          throw redirect({ to: "/force-change-password" });
        }

        if (
          result.ChallengeName === "SMS_MFA" ||
          result.ChallengeName === "SOFTWARE_TOKEN_MFA"
        ) {
          await txSession.update({
            ...txSession.data,
            challengeName: result.ChallengeName,
            challengeSession: result.Session,
            challengeUsername: data.email,
          });
          throw redirect({ to: "/mfa-challenge" });
        }

        await setAuthCookie(result.AuthenticationResult);
        const claims = result.AuthenticationResult?.IdToken
          ? decodeIdTokenClaims(result.AuthenticationResult.IdToken)
          : { sub: data.email, email: data.email, email_verified: false };
        redirectToClient(oauthRequest, claims);
      } catch (err) {
        rethrowIfRedirect(err);
        if (err instanceof Error && err.name === "UserNotConfirmedException") {
          await txSession.update({
            ...txSession.data,
            pendingSignupEmail: data.email,
          });
          throw redirect({ to: "/confirm-sign-up" });
        }
        return { error: cognitoErrorMessage(err) };
      }
    } else {
      // Mock path
      if (data.email.includes("mfa")) {
        await txSession.update({
          ...txSession.data,
          challengeName: "SMS_MFA",
          challengeSession: "mock-challenge-session",
