    let app: AppConfig;
    try {
      app = resolveAppConfig(data.app);
    } catch (err) {
      if (err instanceof AppRegistryError) {
        throw new Response("unknown_app", { status: 401 });
      }
      throw err;
    }

    // biome-ignore lint/correctness/useHookAtTopLevel: server function, not a React component
    const refreshSession = await useAppRefreshTokenSession(app);
    const refreshToken = refreshSession.data.refreshToken;

    if (!refreshToken) {
      await clearAppTokenCookies(app);
      throw new Response("missing_refresh_token", { status: 401 });
    }

    if (isMockAuthEnabled()) {
      await writeAppTokenCookies(app, {
        accessToken: `mock-access-${randomUUID()}`,
        idToken: `mock-id-${randomUUID()}`,
        refreshToken,
      });
      return { ok: true };
    }

    const { clientId } = getCognitoConfig();
    const targetClientId = app.cognitoClientId ?? clientId;

    try {
      const response = await getCognitoClient().send(
        new (await import("@aws-sdk/client-cognito-identity-provider")).InitiateAuthCommand(
          {
            AuthFlow: "REFRESH_TOKEN_AUTH",
            ClientId: targetClientId,
            AuthParameters: {
              REFRESH_TOKEN: refreshToken,
            },
          },
        ),
      );
      const auth = response.AuthenticationResult;
      if (!auth?.AccessToken || !auth?.IdToken) {
        await clearAppTokenCookies(app);
        throw new Response("refresh_failed", { status: 401 });
      }
      await writeAppTokenCookies(app, {
        accessToken: auth.AccessToken,
        idToken: auth.IdToken,
        refreshToken: auth.RefreshToken ?? refreshToken,
        expiresIn: auth.ExpiresIn,
      });
      return { ok: true };
    } catch (err) {
      if (err instanceof Response) throw err;
      await clearAppTokenCookies(app);
      throw new Response("refresh_failed", { status: 401 });
    }
  });

