  async () => {
    await fetch(`${env.VITE_AUTH_APP_URL}/logout`, { method: "POST" });

    const [authTokenSession, refreshTokenSession, accountSession] =
      await Promise.all([
        useAuthTokenSession(),
        useRefreshTokenSession(),
        useAccountSession(),
      ]);

    const leftovers = [
      authTokenSession.data.authToken ? "authToken" : null,
      refreshTokenSession.data.refreshToken ? "refreshToken" : null,
      accountSession.data.accountId ? "__session" : null,
    ].filter((name): name is string => name !== null);

    if (leftovers.length > 0) {
      logServerErrorToRollbar(
        new Error(
          `auth cookies not cleared after /logout: ${leftovers.join(", ")}`,
        ),
      );
    }
  },
);

