  }
});

const buildLoginUrlFn = createServerFn({ method: "POST" })
  .inputValidator((value: unknown) => {
    if (
      !value ||
      typeof value !== "object" ||
      typeof (value as { returnTo?: unknown }).returnTo !== "string"
    ) {
      throw new Error("returnTo (string) is required.");
    }
    return value as { returnTo: string };
  })
  .handler(async ({ data }) => {
    return buildAuthAppLoginUrl(data.returnTo);
  });

export async function initiateLogin(returnTo = "/"): Promise<void> {
  const url = await buildLoginUrlFn({ data: { returnTo } });
  window.location.assign(url);
}

