  async () => {
    return { logoutUrl: buildAuthAppLogoutUrl("/login?logged_out=1") };
  },
);

export async function initiateLogout(): Promise<void> {
  const { logoutUrl } = await performLogout();
  window.location.assign(logoutUrl);
}

