import { env } from "@/env";
import { createHmac, randomUUID, timingSafeEqual } from "node:crypto";
import { createServerOnlyFn } from "@tanstack/react-start";

const APP_SLUG = "org-next";
const AUTH_STATE_TTL_SECONDS = 600;

type AuthStatePayload = {
  slug: string;
  returnTo: string;
  nonce: string;
  iat: number;
};

function base64url(input: string | Buffer): string {
  return Buffer.from(input).toString("base64url");
}

function fromBase64url(value: string): Buffer {
  return Buffer.from(value, "base64url");
}

function hmacSign(secret: string, data: string): string {
  return createHmac("sha256", secret).update(data).digest("base64url");
}

function isRelativePath(value: string): boolean {
  if (typeof value !== "string" || value.length === 0) return false;
  if (!value.startsWith("/")) return false;
  if (value.startsWith("//")) return false;
  if (value.includes("\\")) return false;
  return true;
}

export const buildAuthAppLoginUrl = createServerOnlyFn(
  (returnTo: string): string => {
    const safeReturnTo = isRelativePath(returnTo) ? returnTo : "/";
    const payload: AuthStatePayload = {
      slug: APP_SLUG,
      returnTo: safeReturnTo,
      nonce: randomUUID(),
      iat: Math.floor(Date.now() / 1000),
    };
    const body = base64url(JSON.stringify(payload));
    const sig = hmacSign(env.SESSION_SECRET, body);
    const authState = `${body}.${sig}`;

    const url = new URL("/authorize", env.VITE_AUTH_APP_URL);
    url.searchParams.set("app", APP_SLUG);
    url.searchParams.set("return_to", safeReturnTo);
    url.searchParams.set("auth_state", authState);
    return url.toString();
  },
);

export const buildAuthAppLogoutUrl = createServerOnlyFn(
  (returnTo: string): string => {
    const safeReturnTo = isRelativePath(returnTo) ? returnTo : "/login";
    const url = new URL("/logout", env.VITE_AUTH_APP_URL);
    url.searchParams.set("app", APP_SLUG);
    url.searchParams.set("return_to", safeReturnTo);
    return url.toString();
  },
);

export type VerifyAuthStateResult =
  | { ok: true; payload: AuthStatePayload }
  | {
      ok: false;
      reason:
        | "malformed"
        | "bad_signature"
        | "slug_mismatch"
        | "expired"
        | "invalid_payload";
    };

export const verifyAuthAppState = createServerOnlyFn(
  (token: string, options: { nowSeconds?: number; maxAgeSeconds?: number } = {}): VerifyAuthStateResult => {
    if (typeof token !== "string" || token.length === 0) {
      return { ok: false, reason: "malformed" };
    }
    const parts = token.split(".");
    if (parts.length !== 2) {
      return { ok: false, reason: "malformed" };
    }
    const [body, providedSig] = parts;
    const expectedSig = hmacSign(env.SESSION_SECRET, body);
    const a = fromBase64url(providedSig);
    const b = fromBase64url(expectedSig);
    if (a.length !== b.length || !timingSafeEqual(a, b)) {
      return { ok: false, reason: "bad_signature" };
    }

    let payload: AuthStatePayload;
    try {
      const decoded = JSON.parse(fromBase64url(body).toString("utf8"));
      if (
        !decoded ||
        typeof decoded !== "object" ||
        typeof decoded.slug !== "string" ||
        typeof decoded.returnTo !== "string" ||
        typeof decoded.nonce !== "string" ||
        typeof decoded.iat !== "number"
      ) {
        return { ok: false, reason: "invalid_payload" };
      }
      payload = decoded as AuthStatePayload;
    } catch {
      return { ok: false, reason: "invalid_payload" };
    }

    if (payload.slug !== APP_SLUG) {
      return { ok: false, reason: "slug_mismatch" };
    }
    const now = options.nowSeconds ?? Math.floor(Date.now() / 1000);
    const maxAge = options.maxAgeSeconds ?? AUTH_STATE_TTL_SECONDS;
    if (now - payload.iat > maxAge) {
      return { ok: false, reason: "expired" };
    }
    return { ok: true, payload };
  },
);

