import { env } from "@/env";
import { createServerOnlyFn } from "@tanstack/react-start";
import { useSession } from "@tanstack/react-start/server";

const isSecure = import.meta.env.MODE === "production";

export const useAuthTokenSession = createServerOnlyFn(() => {
  return useSession<{ authToken?: string }>({
    password: env.SESSION_SECRET,
    name: "authToken",
    cookie: {
      httpOnly: true,
      sameSite: "lax",
      secure: isSecure,
      maxAge: 3500,
      path: "/",
    },
  });
});

export const useRefreshTokenSession = createServerOnlyFn(() => {
  return useSession<{ refreshToken?: string }>({
    password: env.SESSION_SECRET,
    name: "refreshToken",
    cookie: {
      httpOnly: true,
      sameSite: "lax",
      secure: isSecure,
      maxAge: 3600 * 24 * 30,
      path: "/",
    },
  });
});

export const useIdTokenSession = createServerOnlyFn(() => {
  return useSession<{ idToken?: string }>({
    password: env.SESSION_SECRET,
    name: "idToken",
    cookie: {
      httpOnly: true,
      sameSite: "lax",
      secure: isSecure,
      maxAge: 3500,
      path: "/",
    },
  });
});

import { afterEach, beforeEach, describe, expect, it } from "vitest";
import {
  AppRegistryError,
  isAllowedReturnTo,
  listAppSlugs,
  pickReturnToTarget,
  resolveAppConfig,
  signAuthState,
  tryResolveAppConfig,
  verifyAuthState,
} from "./app-integration";

const ORIGINAL_AUTH_APPS = process.env.AUTH_APPS;
const ORIGINAL_TEST_APP_SECRET = process.env.TEST_APP_SECRET;

const TEST_APP_SECRET = "x".repeat(48);

const writeRegistry = (config: Record<string, unknown>) => {
  process.env.AUTH_APPS = JSON.stringify(config);
};

beforeEach(() => {
  process.env.TEST_APP_SECRET = TEST_APP_SECRET;
  writeRegistry({
    "test-app": {
      sessionSecretEnv: "TEST_APP_SECRET",
      allowedOrigins: ["http://localhost:9999"],
      cookieNames: { auth: "authToken", refresh: "refreshToken", id: "idToken" },
      cookieDomain: "",
    },
  });
});

afterEach(() => {
  if (ORIGINAL_AUTH_APPS === undefined) {
    delete process.env.AUTH_APPS;
  } else {
    process.env.AUTH_APPS = ORIGINAL_AUTH_APPS;
  }
  if (ORIGINAL_TEST_APP_SECRET === undefined) {
    delete process.env.TEST_APP_SECRET;
  } else {
    process.env.TEST_APP_SECRET = ORIGINAL_TEST_APP_SECRET;
  }
});

describe("resolveAppConfig", () => {
  it("returns config for a known slug", () => {
    const app = resolveAppConfig("test-app");
    expect(app.slug).toBe("test-app");
    expect(app.allowedOrigins).toEqual(["http://localhost:9999"]);
    expect(app.cookieNames).toEqual({
      auth: "authToken",
      refresh: "refreshToken",
      id: "idToken",
    });
    expect(app.sessionSecret).toBe(TEST_APP_SECRET);
    expect(app.returnToPolicy.kind).toBe("relative-only");
  });

  it("throws AppRegistryError(unknown_app) for unknown slug", () => {
    expect(() => resolveAppConfig("missing")).toThrow(AppRegistryError);
    try {
      resolveAppConfig("missing");
    } catch (err) {
      expect((err as AppRegistryError).reason).toBe("unknown_app");
    }
  });

  it("throws AppRegistryError(missing_env) when AUTH_APPS is unset", () => {
    delete process.env.AUTH_APPS;
    expect(() => resolveAppConfig("test-app")).toThrow(AppRegistryError);
  });

  it("throws AppRegistryError(missing_secret) when sessionSecretEnv is missing", () => {
    delete process.env.TEST_APP_SECRET;
    try {
      resolveAppConfig("test-app");
      expect.unreachable("should have thrown");
    } catch (err) {
      expect((err as AppRegistryError).reason).toBe("missing_secret");
    }
  });

  it("accepts inline sessionSecret", () => {
    writeRegistry({
      "test-app": {
        sessionSecret: "y".repeat(40),
        allowedOrigins: ["http://localhost:9999"],
      },
    });
    const app = resolveAppConfig("test-app");
    expect(app.sessionSecret).toBe("y".repeat(40));
  });

  it("rejects too-short sessionSecretEnv values", () => {
    process.env.TEST_APP_SECRET = "too-short";
    try {
      resolveAppConfig("test-app");
      expect.unreachable("should have thrown");
    } catch (err) {
      expect((err as AppRegistryError).reason).toBe("missing_secret");
    }
  });

  it("falls back to default cookie names when omitted", () => {
    writeRegistry({
      "test-app": {
        sessionSecretEnv: "TEST_APP_SECRET",
        allowedOrigins: ["http://localhost:9999"],
      },
    });
    expect(resolveAppConfig("test-app").cookieNames).toEqual({
      auth: "authToken",
      refresh: "refreshToken",
      id: "idToken",
    });
  });

  it("supports allowed-origins return_to policy", () => {
    writeRegistry({
      "test-app": {
        sessionSecretEnv: "TEST_APP_SECRET",
        allowedOrigins: ["http://localhost:9999"],
        returnToPolicy: { allowedOrigins: ["http://localhost:9999"] },
      },
    });
    expect(resolveAppConfig("test-app").returnToPolicy).toEqual({
      kind: "allowed-origins",
      allowedOrigins: ["http://localhost:9999"],
    });
  });
});

describe("tryResolveAppConfig", () => {
  it("returns null for unknown slug", () => {
    expect(tryResolveAppConfig("nope")).toBeNull();
  });

  it("returns config for known slug", () => {
    expect(tryResolveAppConfig("test-app")).not.toBeNull();
  });
});

describe("listAppSlugs", () => {
  it("lists slugs from AUTH_APPS", () => {
    writeRegistry({
      "test-app": { sessionSecretEnv: "TEST_APP_SECRET", allowedOrigins: [] },
      "other-app": { sessionSecret: "z".repeat(40), allowedOrigins: [] },
    });
    expect(listAppSlugs().sort()).toEqual(["other-app", "test-app"]);
  });

  it("returns empty when AUTH_APPS is unset", () => {
    delete process.env.AUTH_APPS;
    expect(listAppSlugs()).toEqual([]);
  });
});

describe("isAllowedReturnTo (relative-only)", () => {
  const app = () => resolveAppConfig("test-app");

  it("accepts simple relative paths", () => {
    expect(isAllowedReturnTo(app(), "/")).toBe(true);
    expect(isAllowedReturnTo(app(), "/home")).toBe(true);
    expect(isAllowedReturnTo(app(), "/path/with?query=1")).toBe(true);
  });

  it("rejects protocol-relative URLs", () => {
    expect(isAllowedReturnTo(app(), "//evil.com/path")).toBe(false);
  });

  it("rejects backslashes anywhere", () => {
    expect(isAllowedReturnTo(app(), "/\\evil")).toBe(false);
    expect(isAllowedReturnTo(app(), "/path\\to")).toBe(false);
  });

  it("rejects paths that do not start with /", () => {
    expect(isAllowedReturnTo(app(), "home")).toBe(false);
    expect(isAllowedReturnTo(app(), "https://example.com/home")).toBe(false);
  });

  it("rejects empty values", () => {
    expect(isAllowedReturnTo(app(), "")).toBe(false);
  });
});

describe("isAllowedReturnTo (allowed-origins)", () => {
  beforeEach(() => {
    writeRegistry({
      "test-app": {
        sessionSecretEnv: "TEST_APP_SECRET",
        allowedOrigins: ["http://localhost:9999"],
        returnToPolicy: { allowedOrigins: ["http://localhost:9999"] },
      },
    });
  });

  it("accepts URLs whose origin is allowed", () => {
    expect(
      isAllowedReturnTo(resolveAppConfig("test-app"), "http://localhost:9999/path"),
    ).toBe(true);
  });

  it("rejects other origins", () => {
    expect(
      isAllowedReturnTo(resolveAppConfig("test-app"), "https://evil.com/"),
    ).toBe(false);
  });

  it("rejects malformed URLs", () => {
    expect(isAllowedReturnTo(resolveAppConfig("test-app"), "not-a-url")).toBe(
      false,
    );
  });
});

describe("pickReturnToTarget", () => {
  it("prepends first allowed origin for relative-only policy", () => {
    expect(
      pickReturnToTarget(resolveAppConfig("test-app"), "/dashboard"),
    ).toBe("http://localhost:9999/dashboard");
  });

  it("returns absolute URL as-is for allowed-origins policy", () => {
    writeRegistry({
      "test-app": {
        sessionSecretEnv: "TEST_APP_SECRET",
        allowedOrigins: ["http://localhost:9999"],
        returnToPolicy: { allowedOrigins: ["http://localhost:9999"] },
      },
    });
    expect(
      pickReturnToTarget(
        resolveAppConfig("test-app"),
        "http://localhost:9999/x",
      ),
    ).toBe("http://localhost:9999/x");
  });

  it("returns null when return_to is invalid", () => {
    expect(pickReturnToTarget(resolveAppConfig("test-app"), "//bad")).toBeNull();
  });
});

describe("signAuthState / verifyAuthState", () => {
  it("round-trips a valid token", () => {
    const app = resolveAppConfig("test-app");
    const token = signAuthState(app, { slug: app.slug, returnTo: "/home" });
    const result = verifyAuthState(app, token);
    expect(result.ok).toBe(true);
    if (result.ok) {
      expect(result.payload.slug).toBe("test-app");
      expect(result.payload.returnTo).toBe("/home");
      expect(result.payload.nonce).toMatch(/[0-9a-f-]+/);
    }
  });

  it("rejects tampered tokens", () => {
    const app = resolveAppConfig("test-app");
    const token = signAuthState(app, { slug: app.slug, returnTo: "/home" });
    const [body, sig] = token.split(".");
    const tampered = `${body}A.${sig}`;
    const result = verifyAuthState(app, tampered);
    expect(result.ok).toBe(false);
    if (!result.ok) expect(result.reason).toBe("invalid_payload");
  });

  it("rejects wrong-secret signatures", () => {
    const app = resolveAppConfig("test-app");
    const token = signAuthState(app, { slug: app.slug, returnTo: "/home" });
    const otherApp = { ...app, sessionSecret: "q".repeat(40) };
    const result = verifyAuthState(otherApp, token);
    expect(result.ok).toBe(false);
    if (!result.ok) expect(result.reason).toBe("bad_signature");
  });

  it("rejects mismatched slugs", () => {
    const app = resolveAppConfig("test-app");
    const token = signAuthState(app, { slug: app.slug, returnTo: "/home" });
    const otherApp = { ...app, slug: "other" };
    const result = verifyAuthState(otherApp, token);
    expect(result.ok).toBe(false);
    if (!result.ok) expect(result.reason).toBe("bad_signature");
  });

  it("rejects expired tokens", () => {
    const app = resolveAppConfig("test-app");
    const past = Math.floor(Date.now() / 1000) - 999_999;
    const token = signAuthState(app, {
      slug: app.slug,
      returnTo: "/home",
      iat: past,
    });
    const result = verifyAuthState(app, token);
    expect(result.ok).toBe(false);
    if (!result.ok) expect(result.reason).toBe("expired");
  });

  it("rejects malformed tokens", () => {
    const app = resolveAppConfig("test-app");
    expect(verifyAuthState(app, "not-a-token").ok).toBe(false);
    expect(verifyAuthState(app, "").ok).toBe(false);
  });
});

