import {
  authorizeSearchSchema,
  isAppAuthorize,
  isAppLogout,
  logoutSearchSchema,
} from "./contracts";

describe("authorizeSearchSchema (oauth mode)", () => {
  it("accepts https redirect_uri values", () => {
    const result = authorizeSearchSchema.safeParse({
      client_id: "local-client",
