      client_id: "local-client",
      redirect_uri: "javascript:alert(1)",
      response_type: "code",
      scope: "openid email profile",
      state: "state-123",
    });

    expect(result.success).toBe(false);
  });
});

describe("authorizeSearchSchema (app mode)", () => {
  it("accepts app/return_to/auth_state without client_id/redirect_uri", () => {
    const result = authorizeSearchSchema.safeParse({
      app: "test-app",
      return_to: "/dashboard",
      auth_state: "signed-state",
    });

    expect(result.success).toBe(true);
    if (result.success) {
      expect(isAppAuthorize(result.data)).toBe(true);
      if (isAppAuthorize(result.data)) {
        expect(result.data.app).toBe("test-app");
        expect(result.data.return_to).toBe("/dashboard");
      }
    }
  });

  it("rejects app mode without auth_state", () => {
    const result = authorizeSearchSchema.safeParse({
      app: "test-app",
      return_to: "/",
    });
    expect(result.success).toBe(false);
  });

  it("rejects app mode without return_to", () => {
    const result = authorizeSearchSchema.safeParse({
      app: "test-app",
      auth_state: "x",
    });
    expect(result.success).toBe(false);
  });
});

