function isProduction(): boolean {
  return process.env.NODE_ENV === "production";
}

function cookieDomainOption(app: AppConfig): string | undefined {
  return app.cookieDomain && app.cookieDomain.length > 0
    ? app.cookieDomain
    : undefined;
}

export async function useAppAuthTokenSession(app: AppConfig) {
  return useSession<AppAuthCookieState>({
    name: app.cookieNames.auth,
    password: app.sessionSecret,
    cookie: {
      domain: cookieDomainOption(app),
      httpOnly: true,
      maxAge: ACCESS_TOKEN_DEFAULT_TTL,
      path: "/",
      sameSite: "lax",
      secure: isProduction(),
    },
  });
}

export async function useAppRefreshTokenSession(app: AppConfig) {
  return useSession<AppRefreshCookieState>({
    name: app.cookieNames.refresh,
    password: app.sessionSecret,
    cookie: {
      domain: cookieDomainOption(app),
      httpOnly: true,
      maxAge: REFRESH_TOKEN_DEFAULT_TTL,
      path: "/",
      sameSite: "lax",
      secure: isProduction(),
    },
  });
}

export async function useAppIdTokenSession(app: AppConfig) {
  return useSession<AppIdCookieState>({
    name: app.cookieNames.id,
    password: app.sessionSecret,
    cookie: {
      domain: cookieDomainOption(app),
      httpOnly: true,
      maxAge: ID_TOKEN_DEFAULT_TTL,
