function isProduction(): boolean {
  return process.env.NODE_ENV === "production";
}

function cookieDomainOption(app: AppConfig): string | undefined {
  return app.cookieDomain && app.cookieDomain.length > 0
    ? app.cookieDomain
    : undefined;
}

export type AppSessionKind = "auth" | "refresh" | "id";

const TTL_BY_KIND: Record<AppSessionKind, number> = {
  auth: ACCESS_TOKEN_DEFAULT_TTL,
  refresh: REFRESH_TOKEN_DEFAULT_TTL,
  id: ID_TOKEN_DEFAULT_TTL,
};

export function appSessionConfig(app: AppConfig, kind: AppSessionKind) {
  return {
    name: app.cookieNames[kind],
    password: app.sessionSecret,
    cookie: {
      domain: cookieDomainOption(app),
      httpOnly: true,
      maxAge: TTL_BY_KIND[kind],
      path: "/",
      sameSite: "lax" as const,
      secure: isProduction(),
    },
  };
}

