import { afterEach, describe, expect, it } from "vitest";
import type { AppConfig } from "./app-integration";
import { appSessionConfig } from "./app-token-cookies";

const ORIGINAL_NODE_ENV = process.env.NODE_ENV;

afterEach(() => {
  if (ORIGINAL_NODE_ENV === undefined) {
    delete process.env.NODE_ENV;
  } else {
    process.env.NODE_ENV = ORIGINAL_NODE_ENV;
  }
});

const baseApp: AppConfig = {
  slug: "test-app",
  allowedOrigins: ["http://localhost:9999"],
  returnToPolicy: { kind: "relative-only" },
  cookieNames: { auth: "authToken", refresh: "refreshToken", id: "idToken" },
  cookieDomain: "",
  sessionSecret: "x".repeat(48),
};

describe("appSessionConfig", () => {
  it("uses configured cookie names per kind", () => {
    expect(appSessionConfig(baseApp, "auth").name).toBe("authToken");
    expect(appSessionConfig(baseApp, "refresh").name).toBe("refreshToken");
    expect(appSessionConfig(baseApp, "id").name).toBe("idToken");
  });

  it("respects custom cookie names", () => {
    const app: AppConfig = {
      ...baseApp,
      cookieNames: { auth: "myAuth", refresh: "myRefresh", id: "myId" },
    };
    expect(appSessionConfig(app, "auth").name).toBe("myAuth");
    expect(appSessionConfig(app, "refresh").name).toBe("myRefresh");
    expect(appSessionConfig(app, "id").name).toBe("myId");
  });

  it("uses the app's session secret as the cookie password", () => {
    expect(appSessionConfig(baseApp, "auth").password).toBe(baseApp.sessionSecret);
  });

  it("omits cookie domain when blank", () => {
    expect(appSessionConfig(baseApp, "auth").cookie.domain).toBeUndefined();
  });

  it("passes through cookie domain when configured", () => {
    const app: AppConfig = { ...baseApp, cookieDomain: ".anedot.com" };
    expect(appSessionConfig(app, "auth").cookie.domain).toBe(".anedot.com");
  });

  it("sets secure=false outside production", () => {
    process.env.NODE_ENV = "development";
    expect(appSessionConfig(baseApp, "auth").cookie.secure).toBe(false);
  });

  it("sets secure=true in production", () => {
    process.env.NODE_ENV = "production";
    expect(appSessionConfig(baseApp, "auth").cookie.secure).toBe(true);
  });

  it("uses different TTLs for refresh vs auth/id", () => {
    expect(appSessionConfig(baseApp, "refresh").cookie.maxAge).toBeGreaterThan(
      appSessionConfig(baseApp, "auth").cookie.maxAge,
    );
  });
});

