const TEST_APP_SLUG = "test-app";
const TEST_APP_ALLOWED_ORIGIN = "http://localhost:3210";

function base64url(value: string | Buffer): string {
  return Buffer.from(value).toString("base64url");
}

function getTestAppSecret(): string {
  const secret = process.env.TEST_APP_SECRET;
  if (!secret || secret.length < 32) {
    throw new Error("TEST_APP_SECRET is not set or too short for tests.");
  }
  return secret;
}

export function signTestAppAuthState(
  returnTo: string,
  options: { slug?: string; iat?: number } = {},
): string {
  const slug = options.slug ?? TEST_APP_SLUG;
  const payload = {
    slug,
    returnTo,
    nonce: randomUUID(),
    iat: options.iat ?? Math.floor(Date.now() / 1000),
  };
  const body = base64url(JSON.stringify(payload));
  const sig = createHmac("sha256", getTestAppSecret())
    .update(body)
    .digest("base64url");
  return `${body}.${sig}`;
}

export function buildAppAuthorizeUrl(
  returnTo = "/dashboard",
