import { expect, test } from "@playwright/test";
import {
  buildAppAuthorizeUrl,
  mockTestAppOrigin,
  signTestAppAuthState,
  startSignIn,
  submitSignIn,
  testAppOrigin,
  testAppSlug,
} from "./helpers";

test.describe("app-mode authorize", () => {
  test("redirects to sign-in for an unauthenticated user", async ({ page }) => {
    await page.goto(buildAppAuthorizeUrl("/dashboard"));
    await expect(page).toHaveURL(/\/sign-in/);
    await expect(page.getByLabel("Email")).toBeVisible();
  });

  test("rejects unknown app slug", async ({ page }) => {
    const search = new URLSearchParams({
      app: "not-registered",
      return_to: "/dashboard",
      auth_state: signTestAppAuthState("/dashboard"),
    });
    await page.goto(`/authorize?${search.toString()}`);
    await expect(page).toHaveURL(/\/error.*reason=unknown_app/);
  });

  test("rejects tampered auth_state", async ({ page }) => {
    const valid = signTestAppAuthState("/dashboard");
    const [body, sig] = valid.split(".");
    const tampered = `${body}A.${sig}`;
    const search = new URLSearchParams({
      app: testAppSlug,
      return_to: "/dashboard",
      auth_state: tampered,
    });
    await page.goto(`/authorize?${search.toString()}`);
    await expect(page).toHaveURL(/\/error.*reason=invalid_auth_state/);
  });

  test("rejects protocol-relative return_to", async ({ page }) => {
    const search = new URLSearchParams({
      app: testAppSlug,
      return_to: "//evil.com/path",
      auth_state: signTestAppAuthState("//evil.com/path"),
    });
    await page.goto(`/authorize?${search.toString()}`);
    await expect(page).toHaveURL(/\/error.*reason=invalid_return_to/);
  });

  test("redirects to validated return_to on the app's origin after sign-in", async ({
    page,
  }) => {
    await mockTestAppOrigin(page);
    await page.goto(buildAppAuthorizeUrl("/dashboard"));
    await expect(page).toHaveURL(/\/sign-in/);
    await submitSignIn(page, "user@example.com");
    await expect(page).toHaveURL(`${testAppOrigin}/dashboard`);
  });

  test("logout in app mode redirects to validated return_to", async ({
    page,
  }) => {
    await mockTestAppOrigin(page);
    await mockTestAppOrigin(page);

    // Sign in via app mode first.
    await page.goto(buildAppAuthorizeUrl("/"));
    await startSignIn(page);
    await submitSignIn(page, "user@example.com");
    await expect(page).toHaveURL(`${testAppOrigin}/`);

    const search = new URLSearchParams({
      app: testAppSlug,
      return_to: "/login?logged_out=1",
    });
    await page.goto(`/logout?${search.toString()}`);
    await expect(page).toHaveURL(`${testAppOrigin}/login?logged_out=1`);
  });
});

