import {
  useAuthTokenSession,
  useIdTokenSession,
  useRefreshTokenSession,
} from "@/server/session.server";
import { createFileRoute } from "@tanstack/react-router";

const isEnabled = process.env.E2E_TEST_SEED === "true";

export const Route = createFileRoute("/test-seed/auth")({
  component: () => null,
  loader: async ({ location }) => {
    if (!isEnabled) {
      throw new Response("test seed disabled", { status: 404 });
    }
    const params = new URLSearchParams(location.search);
    const action = params.get("action") ?? "set";

    if (action === "clear") {
      // biome-ignore lint/correctness/useHookAtTopLevel: server function, not a React component
      const auth = await useAuthTokenSession();
      // biome-ignore lint/correctness/useHookAtTopLevel: server function, not a React component
      const refresh = await useRefreshTokenSession();
      // biome-ignore lint/correctness/useHookAtTopLevel: server function, not a React component
      const id = await useIdTokenSession();
      await auth.clear();
      await refresh.clear();
      await id.clear();
      return { ok: true };
    }

    const authToken = params.get("authToken") ?? "test-access-token";
    const idToken = params.get("idToken") ?? "test-id-token";
    const refreshToken = params.get("refreshToken");

    // biome-ignore lint/correctness/useHookAtTopLevel: server function, not a React component
    const auth = await useAuthTokenSession();
    await auth.update({ authToken });

    // biome-ignore lint/correctness/useHookAtTopLevel: server function, not a React component
    const id = await useIdTokenSession();
    await id.update({ idToken });

    if (refreshToken) {
      // biome-ignore lint/correctness/useHookAtTopLevel: server function, not a React component
      const refresh = await useRefreshTokenSession();
      await refresh.update({ refreshToken });
    }

    return { ok: true };
  },
});

