import { test as base, type Page } from "@playwright/test";
import { MockClient } from "request-mocking-protocol";

// Matches the flag `src/routes/__root.tsx` sets in its hydration `useEffect`.
// Clicking or filling before React has attached listeners makes submit
// buttons trigger native form submission, dropdowns no-op, etc. We can't rely
// on `waitUntil: "networkidle"` here because Vite's dev HMR websocket and
// devtools keep producing low-frequency traffic, so instead we wait for the
// app itself to signal that the client bundle has run.
async function waitForAppHydrated(page: Page): Promise<void> {
  await page.waitForFunction(
    () => (window as { __HYDRATED__?: boolean }).__HYDRATED__ === true,
  );
}

/**
 * Seed the org-next session cookies (authToken, idToken, optionally
 * refreshToken) by hitting the test-only `/test-seed/auth` route, which
 * uses the same `useSession` machinery production code uses, producing
 * properly-signed cookies the rest of the app accepts.
 */
async function seedAuthCookies(
  page: Page,
  options: {
    authToken?: string;
    idToken?: string;
    refreshToken?: string | null;
  } = {},
): Promise<void> {
  const params = new URLSearchParams({
    authToken: options.authToken ?? "test-access-token",
    idToken: options.idToken ?? "test-id-token",
  });
  if (options.refreshToken) {
    params.set("refreshToken", options.refreshToken);
  }
  const response = await page.request.get(
    `/test-seed/auth?${params.toString()}`,
  );
  if (!response.ok()) {
    throw new Error(
      `Failed to seed auth cookies: ${response.status()} ${await response.text()}`,
    );
  }
}

