import { createFileRoute } from "@tanstack/react-router";
import { createServerFn } from "@tanstack/react-start";
import { z } from "zod";

const testSeedInputSchema = z.object({
  action: z.enum(["set", "clear"]).optional(),
  authToken: z.string().optional(),
  idToken: z.string().optional(),
  refreshToken: z.string().optional(),
});

const testSeedAuthCookies = createServerFn({ method: "POST" })
  .inputValidator(testSeedInputSchema)
  .handler(async ({ data }) => {
    if (process.env.E2E_TEST_SEED !== "true") {
      throw new Response("test seed disabled", { status: 404 });
    }
    const session = await import("@/server/session.server");
    const auth = await session.useAuthTokenSession();
    const refresh = await session.useRefreshTokenSession();
    const id = await session.useIdTokenSession();

    if (data.action === "clear") {
      await auth.clear();
      await refresh.clear();
      await id.clear();
      return { ok: true };
    }

    await auth.update({
      authToken: data.authToken ?? "test-access-token",
    });
    await id.update({ idToken: data.idToken ?? "test-id-token" });

    if (data.refreshToken) {
      await refresh.update({ refreshToken: data.refreshToken });
    }

    return { ok: true };
  });

export const Route = createFileRoute("/test-seed/auth")({
  component: () => null,
  loader: async ({ location }) => {
    const params = new URLSearchParams(location.search);
    const action =
      params.get("action") === "clear" ? ("clear" as const) : ("set" as const);
    const authToken = params.get("authToken") ?? undefined;
    const idToken = params.get("idToken") ?? undefined;
    const refreshToken = params.get("refreshToken") ?? undefined;

    return await testSeedAuthCookies({
      data: { action, authToken, idToken, refreshToken },
    });
  },
});
